578: 		for k, wr := range c.proxy.WatchedResources {
579: 			adsClient.Watches[k] = wr.ResourceNames.UnsortedList()
580: 		}
581: 		c.proxy.RUnlock()
582: 		adsClients.Connected = append(adsClients.Connected, adsClient)
583: 	}
584: 	writeJSON(w, adsClients, req)
585: }
