596: // ConfigDump returns information in the form of the Envoy admin API config dump for the specified proxy
597: // The dump will only contain dynamic listeners/clusters/routes and can be used to compare what an Envoy instance
598: // should look like according to Pilot vs what it currently does look like.
599: func (s *DiscoveryServer) ConfigDump(w http.ResponseWriter, req *http.Request) {
600: 	proxyID, con := s.getDebugConnection(req)
601: 	if con == nil {
602: 		s.errorHandler(w, proxyID, con)
603: 		return
604: 	}
605: 	if ts := s.getResourceTypes(req); len(ts) != 0 {
606: 		resources := s.getConfigDumpByResourceType(con, nil, ts)
607: 		configDump := &admin.ConfigDump{}
608: 		for _, resource := range resources {
609: 			for _, rr := range resource {
610: 				configDump.Configs = append(configDump.Configs, rr.Resource)
611: 			}
612: 		}
613: 		writeJSON(w, configDump, req)
614: 		return
615: 	}
616: 
617: 	if con.proxy.IsZTunnel() {
618: 		resources := s.getConfigDumpByResourceType(con, nil, []string{v3.AddressType})
619: 		configDump := &admin.ConfigDump{}
620: 		for _, resource := range resources {
621: 			for _, rr := range resource {
622: 				configDump.Configs = append(configDump.Configs, rr.Resource)
623: 			}
624: 		}
625: 		writeJSON(w, configDump, req)
626: 		return
627: 	}
628: 
629: 	includeEds := req.URL.Query().Has("include_eds")
630: 	dump, err := s.connectionConfigDump(con, includeEds)
631: 	if err != nil {
632: 		handleHTTPError(w, err)
633: 		return
634: 	}
635: 	writeJSON(w, dump, req)
636: }
