638: func (s *DiscoveryServer) getResourceTypes(req *http.Request) []string {
639: 	if shortTypes := req.URL.Query().Get("types"); shortTypes != "" {
640: 		ts := strings.Split(shortTypes, ",")
641: 
642: 		resourceTypes := sets.New[string]()
643: 		for _, t := range ts {
644: 			rType := v3.GetResourceType(t)
645: 			resourceTypes.Insert(rType)
646: 			// special case for AddressType, include WorkloadType as well
647: 			// because they shared same short type name `WDS`
648: 			if rType == v3.AddressType {
649: 				resourceTypes.Insert(v3.WorkloadType)
650: 			}
651: 		}
652: 
653: 		return resourceTypes.UnsortedList()
654: 	}
655: 	return nil
656: }
