658: func (s *DiscoveryServer) getConfigDumpByResourceType(conn *Connection, req *model.PushRequest, ts []string) map[string][]*discoveryv3.Resource {
659: 	dumps := make(map[string][]*discoveryv3.Resource)
660: 	if req == nil {
661: 		req = &model.PushRequest{Push: conn.proxy.LastPushContext, Start: time.Now(), Full: true, Forced: true}
662: 	}
663: 
664: 	for _, resourceType := range ts {
665: 		w := conn.proxy.GetWatchedResource(resourceType)
666: 		if w == nil {
667: 			// Not watched, skip
668: 			continue
669: 		}
670: 		gen := s.findGenerator(resourceType, conn)
671: 		if gen == nil {
672: 			// No generator found, skip
673: 			continue
674: 		}
675: 		if resource, _, err := gen.Generate(conn.proxy, w, req); err == nil {
676: 			for _, rr := range resource {
677: 				switch resourceType {
678: 				case v3.SecretType:
679: 					// Secrets must be redacted
680: 					secret := &tls.Secret{}
681: 					if err := rr.Resource.UnmarshalTo(secret); err != nil {
682: 						istiolog.Warnf("failed to unmarshal secret: %v", err)
683: 						continue
684: 					}
685: 					if secret.GetTlsCertificate() != nil {
686: 						// When utilizing XDS caching, the resource object is shared, so modifying this would modify the cached item
687: 						// Make a clone
688: 						rr = protomarshal.Clone(rr)
689: 						secret.GetTlsCertificate().PrivateKey = &core.DataSource{
690: 							Specifier: &core.DataSource_InlineBytes{
691: 								InlineBytes: []byte("[redacted]"),
692: 							},
693: 						}
694: 					}
695: 					rr.Resource = protoconv.MessageToAny(secret)
696: 					dumps[resourceType] = append(dumps[resourceType], rr)
697: 				case v3.ExtensionConfigurationType:
698: 					tce := &core.TypedExtensionConfig{}
699: 					if err := rr.GetResource().UnmarshalTo(tce); err != nil {
700: 						istiolog.Warnf("failed to unmarshal extension: %v", err)
701: 						continue
702: 					}
703: 
704: 					switch tce.TypedConfig.TypeUrl {
705: 					case xds.WasmHTTPFilterType:
706: 						w := &wasm.Wasm{}
707: 						if err := tce.TypedConfig.UnmarshalTo(w); err != nil {
708: 							istiolog.Warnf("failed to unmarshal wasm filter: %v", err)
709: 							continue
710: 						}
711: 						// Redact Wasm secret env variable.
712: 						vmenvs := w.GetConfig().GetVmConfig().EnvironmentVariables
713: 						if vmenvs != nil {
714: 							if _, found := vmenvs.KeyValues[model.WasmSecretEnv]; found {
715: 								vmenvs.KeyValues[model.WasmSecretEnv] = "<Redacted>"
716: 							}
717: 						}
718: 						dumps[resourceType] = append(dumps[resourceType], &discoveryv3.Resource{
719: 							Name:     w.Config.Name,
720: 							Resource: protoconv.MessageToAny(w),
721: 						})
722: 					default:
723: 						dumps[resourceType] = append(dumps[resourceType], rr)
724: 					}
725: 				default:
726: 					dumps[resourceType] = append(dumps[resourceType], rr)
727: 				}
728: 			}
729: 		} else {
730: 			istiolog.Warnf("generate failed for request resource type (%v): %v", resourceType, err)
731: 			continue
732: 		}
733: 	}
734: 
735: 	return dumps
736: }
